#include <stdio.h>

int main() {
    int T; 
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N; 
        scanf("%d", &N);
        int cnt = 0;
        for (int i = 0; i < N; ++i) {
            int age; 
            scanf("%d", &age);
            if (age >= 10 && age <= 60) cnt++;
        }
        printf("%d\n", cnt);
    }
    return 0;
}

